// Home Screen
const HomeScreen = () => {
  const navigation = useNavigation();

  // Initialize deep link handler on the root screen
  useDeepLinkHandler();

  const testDeepLinks = [
    { label: 'Profile #123', url: 'myapp://profile/123' },
    { label: 'Payment Confirm', url: 'myapp://payment/confirm' },
    { label: 'Payment Confirm with TX', url: 'myapp://payment/confirm/tx_abc123?amount=49.99&currency=USD' },
    { label: 'Payment History', url: 'myapp://payment/history' },
    { label: 'Campaign Summer2024', url: 'myapp://campaign/summer2024?source=email&medium=newsletter' },
    { label: 'Product #456', url: 'myapp://product/456?ref=push_notification' },
    { label: 'Notification #789', url: 'myapp://notification/789' },
    { label: 'Settings > Privacy', url: 'myapp://settings/privacy' },
  ];

  const simulateDeepLink = (url) => {
    const parsedLink = parseDeepLink(url);
    if (parsedLink) {
      handleDeepLinkNavigation(navigation, parsedLink);
    }
  };

  return (
    <View style={styles.container}>
      <Text style={styles.title}>Deep Link Demo</Text>
      <Text style={styles.subtitle}>Tap to simulate deep links:</Text>
      <View style={styles.linkList}>
        {testDeepLinks.map((link, index) => (
          <TouchableOpacity
            key={index}
            style={styles.linkButton}
            onPress={() => simulateDeepLink(link.url)}
          >
            <Text style={styles.linkLabel}>{link.label}</Text>
            <Text style={styles.linkUrl}>{link.url}</Text>
          </TouchableOpacity>
        ))}
      </View>
    </View>
  );
};

